(132659, 'village-des-sciences-de-villefranche-sur-mer', 'Village des sciences de Villefranche sur Mer', 'Observatoire océanographique, Villefranche sur mer 181 Chemin du Lazaret 06230 Villefranche-sur-Mer', 'Villefranche-sur-Mer', 'FR', 43.696077, 7.306861, NULL, '2016-03-24 09:06:16', '2016-05-23 08:49:08', 0, 79870878, '{"image":"location79870878.jpg","description":{"fr":"La station marine à Villefranche-sur-Mer, dont les statuts furent déposés il y a plus d’un siècle à la préfecture de Nice, est actuellement un des observatoires océanologiques français les plus complets en sciences marines.\\nC’est un centre d’excellence en océanographie, physique et télédétection, en biogéochimie et biologie marine.\\nL’Observatoire Océanologique de Villefranche-sur-Mer (OOV) invite les scolaires et le public à la découverte de ses locaux et de ses principaux sujets d’étude. Les personnels de l’OOV animeront de nombreux stands afin de vous permettre de toucher avec vos mains et de voir avec vos yeux ce qui est au centre de leurs projets de recherche.\\nRenommé pour sa pluridisciplinarité, l’Observatoire Océanologique de Villefranche-sur-Mer est porteur de projets de recherche qui concernent les sujets les plus diversifiés, de l''impact des microplastiques sur la Mer Méditerranée en passant par les méduses et les algues toxiques, de l’étude de l’acidification des océans à la recherche en biologie moléculaire sur les oursins, les méduses, les bactéries et les virus."},"tags":[{"id":1,"label":"village des sciences"}],"website":"http://www.obs-vlfr.fr","phone":null,"links":["https://twitter.com/obsOOV","http://www.lov.obs-vlfr.fr/","http://www.lbdv.obs-vlfr.fr/","http://oov.obs-vlfr.fr/fr/info_pratiques/comment_venir_a_l_observatoire_de_villefranche.html"],"access":{"fr":"entrée libre pour journées grand public (samedi 15 et dimanche 16 14h-17h, journée scolaire sur réservation (vendredi 14) http://oov.obs-vlfr.fr/fr/info_pratiques/comment_venir_a_l_observatoire_de_villefranche.html"},"state":1,"timezone":"Europe/Paris"}', '2016-03-24 09:09:11', 'Alpes-Maritimes', 'Provence-Alpes-Côte d''Azur', NULL, '06230', NULL, 4917),
(132660, 'village-des-sciences-dantibes-juan-les-pins', 'Village des sciences et de l''Innovation d''Antibes Juan les Pins', '60 Chemin des Sables, 06160 Antibes', 'Antibes', 'FR', 43.568357, 7.115731, NULL, '2016-03-24 09:07:01', '2016-07-07 07:25:52', 0, 55081696, '{"image":null,"description":{"fr":"Situé au centre de Juan les Pins, à 150 mètres de la mer, le palais des Congrès d''Antibes Juan les Pins constitue un centre de communication et d''échanges de dernière génération."},"tags":[{"id":1,"label":"village des sciences"}],"phone":null,"links":[],"access":{"fr":"libre"},"state":0,"timezone":"Europe/Paris"}', '2016-03-24 09:09:15', 'Alpes-Maritimes', 'Provence-Alpes-Côte d''Azur', NULL, '06160', NULL, 4917),
