(167461, 'nextdoor619', 'Nextdoor', '43 rue Camille Desmoulins à Issy-les-Moulineaux', 'Issy-les-Moulineaux', 'FR', 48.828348, 2.262904, NULL, '2016-04-07 19:45:16', '2016-08-24 10:09:24', 0, 36426050, '{"image":null,"description":{"fr":"#NextdoorIssyVillage se compose de deux bâtiments d’une surface globale de 7600m2 sur 6 étages au sein du quartier Val de Seine. Cet espace propose des prestations de bureaux  privatifs ou partagés, des espaces collaboratifs dimensionnés selon vos besoins et la croissance de votre activité. N’hésitez pas à nous rendre visite."},"website":"http://nextdoor.fr/Les-lieux/Issy-Village","phone":"09 70 26 16 30","links":["https://twitter.com/Nextdoor_fr"],"access":{"fr":"RER C, Métro 12, T2, Bus, Autolib'', Vélib''"},"state":1,"timezone":null}', '2016-04-07 19:49:35', 'Hauts-de-Seine', 'Île-de-France', NULL, '92130', NULL, 2910),
