(167649, 'musee-francais-de-la-carte-a-jouer735', 'Musée Français de la Carte à Jouer', '16 rue Auguste Gervais Issy-les-Moulineaux', 'Issy-les-Moulineaux', 'FR', 48.822767, 2.273414, NULL, '2016-04-12 21:22:49', '2016-08-22 13:05:49', 0, 38017671, '{"image":"location38017671.jpg","description":{"fr":"Situé à 200 mètres du métro « Marie d’Issy » (ligne 12), le Musée de la Carte à Jouer est le seul établissement français consacré à la carte à jouer.\\n\\nMercredi, jeudi et vendredi : de 11h à 17h.\\nSamedi et dimanche : de 14h à 18h.\\n\\nJuillet : du mercredi au dimanche de 13h à 18h.\\nFermé les jours fériés et au mois d’août.\\nGroupes : sur rendez-vous du mardi au dimanche.\\n\\nMoins de 26 ans : gratuit.\\nAdulte : 4,70€ (3,60 € Isséens et Grand Paris Seine Ouest).\\nTarif réduit : 3,60€ (2,60 € Isséens et Grand Paris Seine Ouest)."},"website":"http://www.museecarteajouer.com","phone":"01 41 23 83 60","links":["https://www.facebook.com/museefrancaiscarteajouer/"],"access":{"fr":"Métro, RER, bus"},"state":1,"timezone":null}', '2016-04-12 21:27:33', 'Hauts-de-Seine', 'Île-de-France', NULL, '92130', NULL, 5600),
