(167999, 'village-des-sciences-sorbonne-universites', 'Village des Sciences Sorbonne Universités', '4 place Jussieu 75005 Paris', 'Paris', 'FR', 48.846418, 2.354844, NULL, '2016-04-19 12:18:15', '2016-04-19 13:58:50', 0, 48907006, '{"image":"location48907006.jpg","description":{"fr":"Village des Sciences Sorbonne Universités, le catalyseur de curiosité et de connaissance ! Plus de 100 scientifiques issus de toutes les disciplines donnent rendez-vous à tout les étudiant-e-s, élèves, familles et curieu-x-ses. "},"tags":[{"id":1,"label":"village des sciences"}],"website":"http://fetedelascience.sorbonne-universites.fr/","phone":"01 44 27 91 57","access":{"fr":"Entrée libre et gratuite de 10 h à 18 h, les 14, 15 et 16 octobre 2016 "},"state":1,"timezone":"Europe/Paris"}', '2016-04-19 12:22:41', 'Paris', 'Île-de-France', 'Paris 5e Arrondissement', '75005', NULL, 4917),
