(168074, 'village-des-sciences-de-touraine-inra-centre-val-de-loire', 'Village des Sciences en Touraine, à l''INRA Centre-Val de Loire', '37380 Nouzilly', 'Nouzilly', 'FR', 47.550116, 0.787239, NULL, '2016-04-20 07:44:10', '2016-09-06 07:19:11', 0, 94075159, '{"image":"location94075159.jpg","description":{"fr":"A l''occasion des 70 ans de l''INRA, le Centre Inra Val de Loire accueille le village des sciences d''Indre-et-Loire. Près de 30 stands, animations, visites de laboratoires, mini-conférences sont proposés par les scientifiques de l''Inra mais également de l''Université de Tours, l''Inserm, le CEA, le CNRS, ainsi que par des animateurs d''associations, de lycéens, ...."},"tags":[{"id":1,"label":"village des sciences"}],"phone":null,"links":[],"access":{},"state":1,"timezone":null,"suggestions":[]}', '2016-04-20 07:47:42', 'Indre-et-Loire', 'Centre-Val de Loire', NULL, '37380', NULL, 4917),
