(170234, 'grenoble515', 'CNRS Délégation Alpes', '25 Rue des Martyrs, Grenoble', 'Grenoble', 'FR', 45.203877, 5.700189, NULL, '2016-05-10 07:40:02', '2016-07-28 12:36:14', 0, 81173059, '{"image":"location81173059.jpg","description":{"fr":"Le Centre national de la recherche scientifique (CNRS) est un organisme public de recherche (Établissement public à caractère scientifique et technologique, placé sous la tutelle du Ministère de l''Éducation nationale, de l''Enseignement supérieur et de la Recherche). Il produit du savoir et met ce savoir au service de la société.\\n\\n<< Accès >>\\n\\nEn tram : Ligne B direction Grenoble Presqu''île, arrêt Grenoble Presqu''île\\nEn vélo : De nombreuses pistes cyclables desservent le lieu\\nEn voiture : Places de parkings à proximité"},"tags":[],"website":"http://www.alpes.cnrs.fr/","phone":"0476881000","links":[],"access":{"fr":"Tram B Grenoble Presqu''île, vélo & voiture"},"state":1,"timezone":"Europe/Paris","suggestions":[]}', '2016-05-10 07:44:07', 'Isère', 'Auvergne-Rhône-Alpes', NULL, '38000', NULL, 4917),
