(198874, 'village-des-sciences-montpellier-centre', 'Village des sciences de Montpellier -Faculté de médecine', '2 rue Ecole de Médecine 34000 Montpellier', 'Montpellier', 'FR', 43.613147, 3.873616, NULL, '2016-06-20 13:25:36', '2016-10-06 15:07:54', 0, 88584192, '{"image":"location88584192.jpg","description":{"fr":"Se laisser tenter par une balade au Village des sciences de Montpellier c’est à coup sûr une belle opportunité pour découvrir, expérimenter, échanger et questionner des chercheurs ! C’est aussi tout un programme ponctué d’animations : démonstrations, expérimentations, projections, conférences, spectacles, jeux, … pour petits et grands. Ce \\"village de toutes les sciences\\"se déploie sur deux lieux montpelliérains emblématiques : la Faculté de médecine et le Jardin des plantes de l’Université de Montpellier. Passionnés de sciences ou simples curieux, en famille ou entre amis, le Village des sciences de Montpellier est un événement à ne pas manquer !\\n\\nVendredi 14 octobre  (réservé aux scolaires)\\nSamedi 15 & dimanche 16 octobre (tout public)"},"tags":[{"id":1,"label":"village des sciences"}],"website":"http://www.umontpellier.fr","phone":"0434433382","links":[],"access":{"fr":"Tram Ligne 4 arrêt Albert 1er-Cathédrale"},"state":1,"timezone":"Europe/Paris","suggestions":[{"stakeholderId":20091,"location":{"image":null,"name":"IUT de Beziers","address":"3 place du 14 juillet - 34500 Béziers","city":"Béziers","region":"Languedoc-Roussillon Midi-Pyrénées","postalCode":"34500","description":{"fr":"L''IUT de Béziers se situe au coeur de la ville, à côté de la médiathèque André Malraux, sur le champs de Mars."},"access":{},"website":"https://www.iutbeziers.fr","timezone":null,"phone":"0467116000","latitude":43.3465771019035,"longitude":3.2221652791912,"tags":[]}}]}', '2016-06-20 13:25:08', 'Hérault', 'Occitanie', NULL, '34000', NULL, 4917),
