(201834, 'ecole-nationale-superieure-dart-de-bourges', 'Galerie La Box, École nationale supérieure d''art de Bourges', '9 Rue Edouard Branly, 18000 Bourges', 'Bourges', 'FR', 47.085777, 2.395124, NULL, '2016-07-27 09:24:31', '2016-10-05 12:22:46', 0, 55039586, '{"image":null,"description":{"fr":"La Box est l''un des principaux outils pédagogiques de l’école nationale supérieure d’art de Bourges. Tous les ans, elle produit une dizaine d’expositions d’artistes français ou étrangers.\\n\\nDepuis plusieurs années, elle confie une partie de sa programmation à de jeunes commissaires invités. Choisis puis suivis par une partie de l''équipe pédagogique de l''école, les curateurs développent un programme véritablement expérimental, intégrant pleinement la présence et la participation des étudiants à chaque étape de leur travail. Sous forme de rendez-vous et de workshops tout au long de l''année, cette programmation donne l''occasion d''initier les étudiants au travail d''exposition des œuvres et d''élaboration d''un ensemble cohérent de présentations. Elle leur permet d''être au plus près des acteurs de la scène contemporaine et de se confronter à la réalité de l''élaboration d''un projet d''exposition."},"website":"http://www.ensa-bourges.fr/index.php/fr/la-box","phone":"02 48 69 78 70","links":[],"access":{},"state":1,"timezone":"Europe/Paris"}', '2016-07-27 09:27:21', 'Cher', 'Centre-Val de Loire', NULL, '18000', NULL, 5303),
(201869, 'place-de-la-republique684', 'place de la République,', 'Paris', 'Paris', 'FR', 48.856680, 2.352224, NULL, '2016-07-27 10:30:47', '2016-07-27 10:32:27', 0, 65213925, '{"image":null,"description":{},"phone":null,"links":[],"access":{},"state":0,"timezone":"Europe/Paris"}', '2016-07-27 10:32:27', 'Paris', 'Île-de-France', 'Paris 4e Arrondissement', '75004', NULL, 5694),
(201908, 'ecole-superieure-dart-des-pyrenees', 'École supérieure d''art des Pyrénées - Pau Tarbes', 'Jardin Massey Place Henri Borde 65000 Tarbes', 'Tarbes', 'FR', 43.232971, 0.078013, NULL, '2016-07-27 12:51:38', '2016-10-04 15:43:12', 0, 47872097, '{"image":null,"description":{"fr":"Née de la réunion des écoles d''art de Pau et de Tarbes, l''École supérieure d''art des Pyrénées — Pau Tarbes propose des formations professionnalisantes reconnues dans le réseau européen de l''enseignement supérieur.\\n\\nL''École supérieure d''art des Pyrénées — Pau Tarbes est un établissement public d’enseignement supérieur artistique dont les études conduisent à des diplômes nationaux : DNA (niveau Bac +3) et DNSEP (Bac +5 homologué au grade de Master).\\n\\nElle dispense des formations « art-céramique » ainsi que « design graphique multimédia ». Les futurs diplômés seront des artistes et des professionnels possédant les outils théoriques et conceptuels ainsi que la maîtrise des pratiques et des techniques nécessaires pour exercer dans les domaines en perpétuelle évolution de l’art, de la culture, de la création visuelle et de la communication."},"website":"http://www.esapyrenees.fr","phone":"05 62 93 10 31","links":[],"access":{},"state":1,"timezone":"Europe/Paris"}', '2016-07-27 12:57:18', 'Hautes-Pyrénées', 'Occitanie', NULL, NULL, NULL, 5303),
